v_todos = [f"{v['r']} - {v['t']}" for v in versos]

res = {c: [] for c in categorias}

for v in versos:
    txt = v["t"].lower()
    ref = f"{v['r']} - {v['t']}"
    for c in categorias:
        if any(k in txt for k in kw.get(c, [])):
            res[c].append(ref)

for c in categorias:
    res[c] = list(dict.fromkeys(res[c]))
    if len(res[c]) < 33:
        faltan = 33 - len(res[c])
        otros = [v for v in v_todos if v not in res[c]]
        res[c].extend(otros[:faltan])

out = {"categorias": categorias, "versiculos": res, "total": len(versos)}
with open("artifacts/versiculos/public/bible_categories.json", "w", encoding="utf-8") as f:
    json.dump(out, f, ensure_ascii=False, separators=(",",":"))

print(f"OK: {len(versos)} versículos, {len(categorias)} categorías")
for c in categorias:
    print(f"  {c}: {len(res[c])}")
